def calculate_discount(order):
    if order.customer.is_vip:
        base = order.total * 0.2
    elif order.total > 1000:
        base = order.total * 0.15
    elif order.customer.is_member:
        base = order.total * 0.1
    else:
        base = 0

    if order.promo_code:
        extra = calculate_promo_benefit(order.promo_code)
    else:
        extra = 0

    return base + extra

def process_request(req):
    if req.method == 'GET':
        if req.user.is_admin:
            if req.params.get('format') == 'json':
                if req.params.get('all'):
                    return get_all_as_json()
                else:
                    return get_recent_as_json()
            elif req.params.get('format') == 'csv':
                if req.params.get('all'):
                    return get_all_as_csv()
                else:
                    return get_recent_as_csv()
        else:
            if req.params.get('format') == 'json':
                return get_user_data_json(req.user)
            else:
                return get_user_data_csv(req.user)
